In `pkg/providers/brew.go`, implement the `checkFormulaeStatus` method. This method should take a slice of formula names, execute `brew info --json=v1 <formula1> <formula2> ...`, parse the JSON output, and return a map indicating which of the provided formulae are currently installed.

```go
// pkg/providers/brew.go
func (p *BrewProvider) checkFormulaeStatus(formulae []string) (map[string]bool, error) {
    if len(formulae) == 0 {
        return make(map[string]bool), nil
    }
    args := []string{"info", "--json=v1"}
    args = append(args, formulae...)
    cmd := exec.Command("brew", args...)
    output, err := cmd.Output()
    if err != nil {
        return nil, fmt.Errorf("failed to run brew info: %w", err)
    }

    var brewInfo []struct {
        Name      string `json:"name"`
        Installed []struct { /* details not needed, just length */ } `json:"installed"`
    }
    if err := json.Unmarshal(output, &brewInfo); err != nil {
        return nil, fmt.Errorf("failed to parse brew info JSON: %w", err)
    }

    status := make(map[string]bool)
    for _, f := range formulae {
        status[f] = false // Initialize all as not installed
    }
    for _, info := range brewInfo {
        if len(info.Installed) > 0 { // If 'installed' array is not empty, package is installed
            status[info.Name] = true
        }
    }
    return status, nil
}
```

