```go
// cmd/state.go or pkg/cli/parser.go
func parseResourceRef(ref string) (name string, itemKey string, hasItemKey bool) {
    re := regexp.MustCompile(`^([^\s\[]+)(?:\[([^\]]+)\])?$`) // Matches 'name' or 'name[key]' 
    matches := re.FindStringSubmatch(ref)
    if len(matches) == 0 {
        return ref, "", false // No match, treat entire ref as name
    }
    name = matches[1]
    if len(matches) > 2 && matches[2] != "" {
        itemKey = matches[2]
        hasItemKey = true
    }
    return name, itemKey, hasItemKey
}

